@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_wrapper">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _wrapper;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import",
            "./_content/sv-ec23b813dde0442cba036a680ca8e214/Components/UserActivityTracker.razor.js");

        await _module.InvokeVoidAsync("init", _wrapper, _dotNetRef, TimeoutSeconds * 1000);
    }

    [JSInvokable]
    public async Task NotifyIdle() => await OnIdle.InvokeAsync();

    [JSInvokable]
    public async Task NotifyActive() => await OnActive.InvokeAsync();

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

let timer = null;
let dotNetRef = null;
let isIdle = false;
let timeoutMs = 0;
let element = null;
let handler = null;

const events = ["mousemove", "keydown", "click", "scroll"];

function resetTimer() {
    clearTimeout(timer);

    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("NotifyActive");
    }

    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("NotifyIdle");
    }, timeoutMs);
}

export function init(el, ref, ms) {
    element = el;
    dotNetRef = ref;
    timeoutMs = ms;
    isIdle = false;

    handler = () => resetTimer();
    events.forEach(e => element.addEventListener(e, handler, { passive: true }));

    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("NotifyIdle");
    }, timeoutMs);
}

export function dispose() {
    clearTimeout(timer);
    if (element && handler) {
        events.forEach(e => element.removeEventListener(e, handler));
    }
    element = null;
    dotNetRef = null;
    handler = null;
}

